const stats = $input.first().json;
const total = stats.total || 0;
const passed = stats.passed || 0;
const failed = stats.failed || 0;
const passRate = total > 0 ? Math.round((passed / total) * 100) : 100;
const emoji = passRate >= 90 ? '🟢' : passRate >= 75 ? '🟡' : '🔴';
const yesterday = new Date();
yesterday.setDate(yesterday.getDate() - 1);
const dateStr = yesterday.toLocaleDateString('en-US', { weekday: 'long', month: 'short', day: 'numeric' });

return [{
  json: {
    blocks: JSON.stringify([
      {
        type: 'header',
        text: { type: 'plain_text', text: `${emoji} Daily CI/CD Report — ${dateStr}`, emoji: true }
      },
      {
        type: 'section',
        fields: [
          { type: 'mrkdwn', text: `*Total Builds:*\n${total}` },
          { type: 'mrkdwn', text: `*Pass Rate:*\n${passRate}%` },
          { type: 'mrkdwn', text: `*Passed:*\n✅ ${passed}` },
          { type: 'mrkdwn', text: `*Failed:*\n❌ ${failed}` }
        ]
      },
      stats.top_failures && stats.top_failures.length > 0 ? {
        type: 'section',
        text: {
          type: 'mrkdwn',
          text: `*Most Failing Pipelines:*\n${stats.top_failures.map(f => `• ${f.name}: ${f.count} failures`).join('\n')}`
        }
      } : null,
      {
        type: 'actions',
        elements: [{
          type: 'button',
          text: { type: 'plain_text', text: 'Open Aeon Dashboard', emoji: true },
          url: 'http://localhost:3000',
          style: 'primary'
        }]
      }
    ].filter(Boolean)),
    text: `CI/CD Report: ${passRate}% pass rate yesterday (${passed}/${total} builds)`
  }
}];
